import React, { createContext, useContext, useState, useEffect } from 'react';
import Cookies from 'js-cookie';
import { useDispatch } from 'react-redux';
import { signin } from '../../actions/auth';
import { validateToken } from '../../actions/auth'; // Importera validateToken-funktionen

const AuthContext = createContext();

export const useAuth = () => {
  console.log("useAuth: ", value.isAuthenticated)
  return useContext(AuthContext);
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(true); // Nytt tillstånd för att indikera om autentiseringen laddas
  const [isAuthenticated, setIsAuthenticated] = useState(false); // Uppdatera detta till false initialt
  const dispatch = useDispatch();

  useEffect(() => {
    const checkAuth = async () => {
      console.log("useEffect")
      setLoading(true); // Ange laddningsstatus när autentiseringen kontrolleras
      const token = Cookies.get('jwtToken');
      
      if (token) {
        try {
          const isValid = await validateToken(token);
          console.log("token i auth: ", token)
          setIsAuthenticated(isValid);
          console.log("true token")
        } catch (error) {
          console.error('Fel vid autentiseringskontroll:', error);
        }
      } else {
        console.log("false token")
        setIsAuthenticated(false); // Om ingen token finns, sätt tillståndet till false
      }
      setLoading(false); // Sluta ladda när autentiseringen är klar
    };
    checkAuth();
  }, []);  

  const login = async (formData, history) => {
    try {
      setError(null);
      await dispatch(signin(formData, history));
      const token = Cookies.get('jwtToken');
      if (token) {
        setIsAuthenticated(true);
        setUser({ username: formData.username });
      } else {
        setError('Ingen autentiseringstoken mottagen efter inloggning.');
      }
    } catch (error) {
      setError(error.message);
    }
  };

  const logout = () => {
    Cookies.remove('jwtToken');
    setIsAuthenticated(false);
  };

  const value = {
    user,
    login,
    logout,
    error,
    isAuthenticated,
    loading, // Lägg till laddningsstatus i kontextvärdet
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};
